 1	{
 2	  "$schema": "http://json-schema.org/draft-07/schema#",
 3	  "$id": "gauntlet/schemas/triage.json",
 4	  "title": "Triage verdicts (PRD §7, FR-5.2)",
 5	  "description": "Point-by-point triager output: one verdict per finding. `finding_id`/`verdict`/`reasoning`/`action` are normative per PRD §7. `confidence` (severity-aware escalation, plan P4 / review F-009), `target_artifact` (upstream-invalidation routing, BOOTSTRAP-NOTES #6 / FR-10.4), and `escalated` (engine-recorded) are P4 schema additions; the PRD §7 excerpt itself is unchanged.",
 6	  "type": "object",
 7	  "additionalProperties": false,
 8	  "required": ["verdicts"],
 9	  "properties": {
10	    "verdicts": {
11	      "type": "array",
12	      "items": {"$ref": "#/definitions/verdict"}
13	    },
14	    "summary": {"type": "string"}
15	  },
16	  "definitions": {
17	    "verdict": {
18	      "type": "object",
19	      "additionalProperties": false,
20	      "required": ["finding_id", "verdict", "reasoning", "action", "confidence", "target_artifact"],
21	      "properties": {
22	        "finding_id": {"type": "string"},
23	        "verdict": {
24	          "type": "string",
25	          "enum": [
26	            "legitimate",
27	            "bikeshedding",
28	            "premature_optimization",
29	            "not_applicable"
30	          ]
31	        },
32	        "reasoning": {
33	          "type": "string",
34	          "description": "1-3 sentences."
35	        },
36	        "action": {
37	          "type": "string",
38	          "enum": ["fix_now", "defer", "reject"]
39	        },
40	        "confidence": {
41	          "type": "string",
42	          "enum": ["high", "medium", "low"],
43	          "description": "Triager self-assessed confidence; `low` escalates to a stronger model or the human gate (review F-009)."
44	        },
45	        "target_artifact": {
46	          "type": ["string", "null"],
47	          "description": "null unless the fix lands in a different artifact than the one reviewed (e.g. a plan finding implicating the PRD); set, FR-10.4 upstream-invalidation routing becomes explicit instead of inferred from reasoning text. Required-but-nullable for native structured-output strict mode (see findings.json note)."
48	        },
49	        "escalated": {
50	          "type": "boolean",
51	          "description": "Engine-recorded: this verdict was re-issued by the escalation agent (or flagged for the human gate). Not produced by the cheap triager itself."
52	        }
53	      }
54	    }
55	  }
56	}

 1	{
 2	  "$schema": "http://json-schema.org/draft-07/schema#",
 3	  "$id": "gauntlet/schemas/confirm.json",
 4	  "title": "Confirm-pass verdicts (FR-9.5)",
 5	  "description": "Diff-scoped confirm output: the reviewer judges, per prior finding, whether the commit-range diff addressed it. `new_findings` lets the confirm pass surface a regression it noticed in the diff without re-reviewing the whole phase.",
 6	  "type": "object",
 7	  "additionalProperties": false,
 8	  "required": ["verdicts", "new_findings", "summary"],
 9	  "properties": {
10	    "verdicts": {
11	      "type": "array",
12	      "items": {
13	        "type": "object",
14	        "additionalProperties": false,
15	        "required": ["finding_id", "verdict", "notes"],
16	        "properties": {
17	          "finding_id": {"type": "string"},
18	          "verdict": {
19	            "type": "string",
20	            "enum": [
21	              "resolved",
22	              "partially_resolved",
23	              "unresolved",
24	              "regression_introduced"
25	            ]
26	          },
27	          "notes": {"type": "string"}
28	        }
29	      }
30	    },
31	    "new_findings": {
32	      "type": "array",
33	      "description": "Defects visible in the round's diff itself (scope: the diff, nothing else).",
34	      "items": {
35	        "type": "object",
36	        "additionalProperties": false,
37	        "required": ["severity", "claim", "location"],
38	        "properties": {
39	          "severity": {"type": "string", "enum": ["blocking", "major", "minor", "nit"]},
40	          "claim": {"type": "string"},
41	          "location": {"type": "string"}
42	        }
43	      }
44	    },
45	    "summary": {"type": "string"}
46	  }
47	}

 1	{
 2	  "$schema": "http://json-schema.org/draft-07/schema#",
 3	  "$id": "gauntlet/schemas/findings.json",
 4	  "title": "Reviewer findings (PRD §7, FR-5.2)",
 5	  "description": "Structured output of an adversarial review step. The `findings` array is normative per PRD §7. `open_questions` and `summary` are P4 schema additions (BOOTSTRAP-NOTES #5): reviewers naturally emit questions that are not claims, and forcing them through the verdict enum is wrong — they get their own slot and the triager handles them first-class. The PRD §7 excerpt itself is unchanged. Strict-mode note (pinned, codex 0.139.0): native structured output requires EVERY property in `required`, so §7-optional fields are spelled required-but-nullable; `suggested_fix: null` means 'none offered'.",
 6	  "type": "object",
 7	  "additionalProperties": false,
 8	  "required": ["findings", "open_questions", "summary"],
 9	  "properties": {
10	    "findings": {
11	      "type": "array",
12	      "items": {
13	        "type": "object",
14	        "additionalProperties": false,
15	        "required": ["id", "severity", "category", "location", "claim", "evidence", "suggested_fix"],
16	        "properties": {
17	          "id": {
18	            "type": "string",
19	            "description": "Stable finding ID, e.g. F-001; referenced by triage and confirm verdicts. Engine-synthesized findings (e.g. a reviewer-mutation record) carry suffixed IDs like F-R1-MUTATION."
20	          },
21	          "severity": {
22	            "type": "string",
23	            "enum": ["blocking", "major", "minor", "nit"]
24	          },
25	          "category": {
26	            "type": "string",
27	            "enum": [
28	              "correctness",
29	              "spec-gap",
30	              "security",
31	              "performance",
32	              "principle-violation",
33	              "style"
34	            ]
35	          },
36	          "location": {
37	            "type": "string",
38	            "description": "File and line/section reference."
39	          },
40	          "claim": {
41	            "type": "string",
42	            "description": "What is wrong."
43	          },
44	          "evidence": {
45	            "type": "string",
46	            "description": "Why the reviewer believes it."
47	          },
48	          "suggested_fix": {
49	            "type": ["string", "null"],
50	            "description": "Optional per §7 — null when the reviewer offers none."
51	          }
52	        }
53	      }
54	    },
55	    "open_questions": {
56	      "type": "array",
57	      "description": "Questions, not claims (BOOTSTRAP-NOTES #5). Triage treats each as data and may convert one into a finding.",
58	      "items": {
59	        "type": "object",
60	        "additionalProperties": false,
61	        "required": ["id", "question"],
62	        "properties": {
63	          "id": {"type": "string", "description": "e.g. OQ-1"},
64	          "question": {"type": "string"}
65	        }
66	      }
67	    },
68	    "summary": {"type": "string"}
69	  }
70	}
